    /// Install shell completions
    Install {
        /// Override shell detection
        #[arg(long, value_enum)]
        shell: Option<ShellArg>,

        /// Show what would be done without doing it
        #[arg(long)]
        dry_run: bool,
    },

    /// Generate completion script to stdout
    Generate {
        /// Shell to generate for
        #[arg(value_enum)]
