### Install Command Implementation

```rust
fn completions_install(shell_override: Option<ShellArg>, dry_run: bool) -> Result<()> {
    let shell = match shell_override {
        Some(s) => s.into(),
        None => {
            let detected = detect_shell();
            if detected == Shell::Unknown {
                anyhow::bail!(
                    "Could not detect shell. Use --shell to specify: bash, zsh, or fish"
                );
            }
            println!("Detected shell: {}", detected.name());
            detected
        }
    };

    let path = install_completions(shell, dry_run)?;

    if !dry_run {
        println!("Installed {} completions to {}", shell.name(), path.display());
        println!("{}", shell.activation_hint());

        // Extra hint for zsh fpath
        if shell == Shell::Zsh {
            if let Some(parent) = path.parent() {
                if !check_zsh_fpath(parent) {
                    println!();
                    println!("Note: You may need to add this to your ~/.zshrc:");
                    println!("  fpath=(~/.zsh/completions $fpath)");
                    println!("  autoload -Uz compinit && compinit");
                }
            }
        }
    }

    Ok(())
}
```

