   ```rust
   #[tokio::test]
   async fn test_suggestions_are_actionable() {
       let harness = TestHarness::with_config(r#"
           [[proxies]]
           id = "bad-proxy"
           url = "http://127.0.0.1:59999"
       "#).await;

       let result = harness.run_command(&["check", "--test-connectivity"]);

       let output = format!("{}{}", result.stdout, result.stderr);

